  '80901':[38.820,38.865,-104.840,-104.790],'80903':[38.820,38.865,-104.840,-104.790],
  '80904':[38.840,38.915,-104.910,-104.840],'80905':[38.795,38.840,-104.870,-104.800],
  '80906':[38.760,38.820,-104.880,-104.790],'80907':[38.860,38.925,-104.845,-104.785],
